export class McpRouterAdapter {
    tools = new Map();
    getToolHandler(name) {
        return this.tools.get(name)?.handler;
    }
    mapTools(callback) {
        return Array.from(this.tools.keys()).map(callback);
    }
    getToolsSchemas() {
        return Array.from(this.tools.keys()).map((name) => this.tools.get(name)?.schema);
    }
    getToolCapabilities() {
        return Array.from(this.tools.keys()).reduce((acc, name) => {
            acc[name] = this.tools.get(name)?.schema;
            return acc;
        }, {});
    }
    setTool({ schema, handler }) {
        this.tools.set(schema.name, { schema, handler });
        return this;
    }
}
